# WRONG: in-memory store breaks with multiple replicas
_runs: dict[str, dict] = {}

@app.post('/runs')
async def create_run_bad(payload):
    run_id = str(uuid.uuid4())
    _runs[run_id] = {'status': 'pending'}  # lost on any other pod
    return {'run_id': run_id}


# CORRECT: persist immediately to Postgres
@app.post('/runs')
async def create_run(payload: RunPayload, db: AsyncSession = Depends(get_db)):
    run = Run(status='pending')
    db.add(run)
    await db.commit()
    run_agent_task.delay(str(run.id), payload.message)
    return {'run_id': str(run.id)}
